    67→          setError(repoError);
    68→          setSaving(false);
    69→          return;
    70→        }
    71→        result.source = {
    72→          provider,
    73→          repository: repository.trim(),
    74→          poll_interval_seconds: Number(pollInterval) || 86400,
    75→          enabled: true,
    76→        };
    77→      }
    78→      await onSubmit(result);
    79→      if (onSuccess) {
    80→        onSuccess();
    81→      } else {
    82→        router.push("/projects");
    83→      }
    84→    } catch (err: unknown) {
    85→      setError(err instanceof Error ? err.message : "Failed to save");
