   154→                  onChange={(e) => setPollInterval(e.target.value)}
   155→                />
   156→              </div>
   157→            </div>
   158→          )}
   159→        </div>
   160→      )}
   161→
   162→      <div className="flex justify-end gap-2">
   163→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   164→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   165→      </div>
   166→    </form>
   167→  );
   168→
   169→  // Dialog mode: return form content without Card wrapper
   170→  if (onSuccess) {
   171→    return formContent;
   172→  }
   173→
   174→  // Page mode: wrap in Card
   175→  return (
   176→    <Card className="mx-auto max-w-2xl">
