   841→            projectId={id}
   842→            onSuccess={() => { setCtxCreateOpen(false); mutateCtx(); }}
   843→            onCancel={() => setCtxCreateOpen(false)}
   844→          />
   845→        </DialogContent>
   846→      </Dialog>
   847→
   848→      {/* Context source delete dialog */}
   849→      <ConfirmDialog
   850→        open={!!deletingCtxId}
   851→        onOpenChange={(open) => { if (!open) setDeletingCtxId(null); }}
   852→        title="Delete Context Source"
   853→        description="This will permanently delete this context source."
   854→        onConfirm={async () => { if (deletingCtxId) { await ctxApi.delete(deletingCtxId); mutateCtx(); } }}
   855→      />
   856→
   857→      {/* Project delete dialog */}
   858→      <ConfirmDialog
   859→        open={deletingProject}
   860→        onOpenChange={setDeletingProject}
   861→        title="Delete Project"
   862→        description="This will permanently delete this project, including all sources, releases, and subscriptions."
   863→        onConfirm={async () => { await projectsApi.delete(id); router.push("/projects"); }}
   864→      />
   865→    </div>
   866→  );
