   242→                      >
   243→                        <Trash2 className="h-4 w-4" />
   244→                      </button>
   245→                    </div>
   246→                  </td>
   247→                </tr>
   248→              ))}
   249→            </tbody>
   250→          </table>
   251→        )}
   252→      </div>
   253→
   254→      {/* Create dialog */}
   255→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   256→        <DialogContent className="sm:max-w-lg">
   257→          <DialogHeader>
   258→            <DialogTitle>Create Subscription</DialogTitle>
   259→          </DialogHeader>
   260→          <SubscriptionForm
   261→            title="Create Subscription"
   262→            onSubmit={async (input) => {
   263→              await subsApi.create(input);
   264→            }}
   265→            onBatchSubmit={async (input) => {
   266→              await subsApi.batchCreate(input);
   267→            }}
   268→            onSuccess={() => {
   269→              setCreateOpen(false);
   270→              mutate("subscriptions");
   271→            }}
   272→            onCancel={() => setCreateOpen(false)}
   273→          />
   274→        </DialogContent>
   275→      </Dialog>
   276→
   277→      {/* Edit dialog */}
   278→      <Dialog
   279→        open={!!editingSub}
   280→        onOpenChange={(open) => {
   281→          if (!open) setEditingSub(null);
   282→        }}
   283→      >
   284→        <DialogContent className="sm:max-w-lg">
   285→          <DialogHeader>
   286→            <DialogTitle>Edit Subscription</DialogTitle>
   287→          </DialogHeader>
   288→          {editingSub && (
   289→            <SubscriptionForm
   290→              key={editingSub.id}
   291→              title="Edit Subscription"
   292→              initial={editingSub}
   293→              onSubmit={async (input) => {
   294→                await subsApi.update(editingSub.id, input);
   295→              }}
   296→              onSuccess={() => {
   297→                setEditingSub(null);
   298→                mutate("subscriptions");
   299→              }}
   300→              onCancel={() => setEditingSub(null)}
   301→            />
   302→          )}
   303→        </DialogContent>
   304→      </Dialog>
   305→
   306→      {/* Delete dialog */}
   307→      <ConfirmDialog
   308→        open={!!deletingId}
   309→        onOpenChange={(open) => {
   310→          if (!open) setDeletingId(null);
   311→        }}
   312→        title="Delete Subscription"
   313→        description="This will permanently delete this subscription. This cannot be undone."
   314→        onConfirm={async () => {
   315→          if (deletingId) {
   316→            await subsApi.delete(deletingId);
   317→            mutate("subscriptions");
   318→          }
   319→        }}
   320→      />
   321→    </div>
   322→  );
   323→}
